import{_ as o,o as t,c as a,ag as r}from"./chunks/framework.DlJzNSsD.js";const g=JSON.parse('{"title":"ClawTerm brand","description":"","frontmatter":{},"headers":[],"relativePath":"brand.md","filePath":"brand.md","lastUpdated":1779215858000}'),n={name:"brand.md"};function s(i,e,d,c,l,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="clawterm-brand" tabindex="-1">ClawTerm brand <a class="header-anchor" href="#clawterm-brand" aria-label="Permalink to &quot;ClawTerm brand&quot;">​</a></h1><p>Source of truth for what ClawTerm <em>is</em> in brand terms — position, voice, color, type, mark, naming, screenshots. Update this file before changing anything user-visible. The CI lints at <code>scripts/lint-tokens.sh</code> and <code>scripts/lint-name.sh</code> enforce the color/font tokens and the brand-name casing; the rest is on us.</p><h2 id="position" tabindex="-1">Position <a class="header-anchor" href="#position" aria-label="Permalink to &quot;Position&quot;">​</a></h2><p>ClawTerm is a Mac-native terminal workspace for focused technical workflows — the best way to run many AI agents at once and keep track of them.</p><p><strong>Reads as:</strong> calm, dense, Mac-native, professional — closer to a system utility than a SaaS dashboard. Agent-aware features (status dots, attention indicators, OSC notifications) feel like instrumentation, not personality.</p><p><strong>Closest references:</strong> Ghostty&#39;s restraint + Linear&#39;s information density + Raycast&#39;s command-palette discipline.</p><p><strong>What we are not:</strong> Warp (block-based, AI-first marketing, gradients, animation flair). iTerm2 (legacy chrome, bevels). Hyper (web-first, theme marketplace, plugin maximalism).</p><h2 id="personality" tabindex="-1">Personality <a class="header-anchor" href="#personality" aria-label="Permalink to &quot;Personality&quot;">​</a></h2><p>Mac-native, technical, calm, focused, precise, minimal.</p><p>Not: loud, cyberpunk, gaming, futuristic, SaaS, decorative.</p><h2 id="voice" tabindex="-1">Voice <a class="header-anchor" href="#voice" aria-label="Permalink to &quot;Voice&quot;">​</a></h2><ul><li>Direct, technical, lowercase-friendly headings.</li><li>No exclamation points, no &quot;10x&quot; copy, no buzzwords.</li><li>Reference voice: the README&#39;s &quot;Highlights&quot; section.</li><li>In-app strings should match that register.</li></ul><h2 id="naming" tabindex="-1">Naming <a class="header-anchor" href="#naming" aria-label="Permalink to &quot;Naming&quot;">​</a></h2><p>The product name is <strong>ClawTerm</strong> — capital T. Not &quot;Clawterm&quot;, not &quot;ClawTerminal&quot;.</p><ul><li>Brand / display name: <strong>ClawTerm</strong></li><li>App bundle / <code>.app</code>: <code>ClawTerm.app</code> for fresh installs</li><li>Bundle id: <code>com.clawterm.terminal</code> (lowercase is fine in identifiers)</li><li>Repo slug / URLs: <code>github.com/clawterm/clawterm</code> (lowercase by convention)</li><li>File paths, npm/cargo crate names, CSS class names, env vars: lowercase <code>clawterm</code> is fine</li></ul><p><code>scripts/lint-name.sh</code> enforces <code>ClawTerm</code> (capital T) in tracked docs/UI files and fails CI on the old <code>Clawterm</code> form. Lowercase <code>clawterm</code> in identifier-safe contexts is allowed by word-boundary matching. <code>docs/brand.md</code> is exempt because it documents both spellings explicitly.</p><h2 id="mark" tabindex="-1">Mark <a class="header-anchor" href="#mark" aria-label="Permalink to &quot;Mark&quot;">​</a></h2><p>Compact 2×2 terminal grid. Three quiet command tiles, each containing a <code>&gt;_</code> prompt glyph. The bottom-right tile is <strong>active</strong>: green prompt glyph, green underline cursor, and a soft green outer glow.</p><p>The active tile is always bottom-right and always Command Green. A regeneration that moves or recolors it is a logo rule violation.</p><p>The canonical raster source is <code>docs/brand/logoclawterm.png</code> (1024×1024). The mark is AI-generated; PNG is the canonical format and the <code>.icns</code> / <code>src-tauri/icons/*.png</code> derivatives are downscaled via <code>sips</code>. A clean hand-built SVG source is a possible follow-up but not required.</p><h2 id="color-system" tabindex="-1">Color system <a class="header-anchor" href="#color-system" aria-label="Permalink to &quot;Color system&quot;">​</a></h2><p>Defined in <code>src/style.css :root</code>. Reference via <code>var(--*)</code> only — the lint script fails CI on hardcoded hex values outside <code>:root</code>.</p><table tabindex="0"><thead><tr><th>Role</th><th>Token</th><th>Value</th><th>Use</th></tr></thead><tbody><tr><td>Background</td><td><code>--bg-base</code></td><td><code>#050607</code></td><td>App background</td></tr><tr><td>Surface</td><td><code>--bg-surface</code></td><td><code>#0B0D0E</code></td><td>Panel surface (terminal interior runs one notch darker, <code>#07080A</code>, set in <code>src/config.ts</code>)</td></tr><tr><td>Panel</td><td><code>--bg-elevated</code></td><td><code>#111315</code></td><td>Sidebar, cards, title bar, focused pane, hover</td></tr><tr><td>Border</td><td><code>--border</code></td><td><code>#22262A</code></td><td>Solid separators</td></tr><tr><td>Border (overlay)</td><td><code>--border-subtle</code> / <code>--border-default</code></td><td>rgba 6% / 9% white</td><td>Subtle overlays on arbitrary surfaces</td></tr><tr><td>Text</td><td><code>--text-primary</code></td><td>rgba(244,244,245,0.9)</td><td>Primary text</td></tr><tr><td>Muted text</td><td><code>--text-secondary</code></td><td>rgba(244,244,245,0.55)</td><td>Secondary text</td></tr><tr><td>Dim text</td><td><code>--text-tertiary</code></td><td>rgba(244,244,245,0.35)</td><td>Tertiary / disabled</td></tr><tr><td><strong>Accent</strong></td><td><code>--accent</code></td><td><strong><code>#7CFF4F</code></strong> Command Green</td><td><strong>Active state only</strong> (see green-usage rule below)</td></tr></tbody></table><h3 id="existing-status-tokens-stay-as-is" tabindex="-1">Existing status tokens stay as is <a class="header-anchor" href="#existing-status-tokens-stay-as-is" aria-label="Permalink to &quot;Existing status tokens stay as is&quot;">​</a></h3><ul><li><code>--color-red</code> <code>#e5484d</code> — error state</li><li><code>--color-green</code> <code>#30a46c</code> — semantic success state (this is <strong>not</strong> Command Green; different semantics)</li><li><code>--color-orange</code> <code>#f5a623</code> — warning state</li><li><code>--color-purple-signal</code> <code>#bf7af0</code> — Claude compaction signal (single special-case hue)</li><li><code>--badge-info-*</code> / <code>--badge-warn-*</code> — footer effort badges</li></ul><p>Adding a new color? Add the token to <code>:root</code>, document semantic intent here, then use it.</p><h3 id="green-usage-rule" tabindex="-1">Green-usage rule <a class="header-anchor" href="#green-usage-rule" aria-label="Permalink to &quot;Green-usage rule&quot;">​</a></h3><p><strong>Command Green <code>#7CFF4F</code> only ever means <em>active / selected / running / ready / focused / executing</em>.</strong> No decorative use.</p><blockquote><p><strong>At most one primary chrome element is green per screen</strong> — active tab, focused pane, primary CTA, or focus ring.</p><p><em>Status indicators</em> (running dots, ready badges, success toasts) may repeat per subject — that&#39;s the indicator doing its job, not decoration.</p></blockquote><p><strong>Allowed uses:</strong> active prompt, terminal cursor, selected workspace, active tab indicator, primary execution action (e.g. &quot;Run&quot;, &quot;Open project&quot;), ready-to-run action, focus ring, running/ready status dots.</p><p><strong>Forbidden uses:</strong> large green backgrounds, decorative glow, marketing gradients, every icon, the full wordmark, hover states on secondary buttons, button emphasis on non-executing actions, &quot;Save&quot; buttons in settings (those are neutral).</p><h2 id="interaction" tabindex="-1">Interaction <a class="header-anchor" href="#interaction" aria-label="Permalink to &quot;Interaction&quot;">​</a></h2><p><strong>Button hover strategy is binary, never mixed (#537):</strong></p><ul><li><strong>Filled accent surfaces</strong> — <code>.btn--primary</code>, <code>.btn--destructive</code> — dim via <code>opacity</code>. The color is already loud; opacity softens without hue drift.</li><li><strong>Surface-tier buttons</strong> — <code>.btn--secondary</code>, <code>.btn--ghost</code>, <code>.btn--icon</code> — lift their background via <code>--bg-hover</code> / <code>--bg-active</code> / <code>--bg-hover-strong</code>. No opacity drops on this tier; no background lifts on the filled-accent tier.</li></ul><p>If a new button needs a third strategy, the answer is to pick the closest existing tier, not to invent one. Tokens for the surface-tier lift ladder live in <code>:root</code> and have semantic names (<code>--bg-hover</code>, <code>--bg-active</code>, <code>--bg-hover-strong</code>) — never reach into another system&#39;s token (e.g. <code>--scrollbar-thumb</code>) as a shortcut.</p><h2 id="type" tabindex="-1">Type <a class="header-anchor" href="#type" aria-label="Permalink to &quot;Type&quot;">​</a></h2><p>ClawTerm is <strong>all-mono</strong>. Every glyph in the app — sidebar labels, buttons, dialog copy, headings, wordmark, terminal — is rendered in <strong>JetBrains Mono</strong>. The aesthetic is the technical voice of the brand: typewriter calm, archival precision, the typeface of well logs and field reports. There is no companion sans.</p><ul><li><strong>UI / body / wordmark:</strong> <code>&quot;JetBrains Mono Variable&quot;, &quot;JetBrains Mono&quot;, &quot;SFMono-Regular&quot;, ui-monospace, &quot;SF Mono&quot;, Menlo, Monaco, Consolas, monospace</code></li><li><strong>Terminal:</strong> same stack.</li><li><strong>Scale:</strong> <code>--font-2xs</code> 8 · <code>--font-xs</code> 10 · <code>--font-sm</code> 11 · <code>--font-base</code> 12 · <code>--font-md</code> 13 · <code>--font-lg</code> 14 · <code>--font-2xl</code> 20</li><li><strong>Weights:</strong> <code>--font-weight-medium</code> 500 · <code>--font-weight-semibold</code> 600 — JetBrains Mono Variable accepts the full 100–800 axis range, but UI surfaces should snap to 400 / 500 / 600 / 700 for predictability.</li><li><strong>Letter-spacing:</strong> <code>--letter-spacing-normal</code> (0) by default — mono is already evenly spaced, no kerning compression. <code>--letter-spacing-wide</code> (0.04em) for uppercase chrome (footer effort badges, status dots).</li><li><strong>Wordmark:</strong> JetBrains Mono, weight 700, letter-spacing 0. No tracking adjustments — the wordmark inherits mono&#39;s natural rhythm.</li></ul><p>Inter is retired. The dependency is removed from <code>package.json</code> and the <code>@font-face</code> block for Inter is dropped from <code>src/fonts.css</code>.</p><h2 id="spacing" tabindex="-1">Spacing <a class="header-anchor" href="#spacing" aria-label="Permalink to &quot;Spacing&quot;">​</a></h2><p>Strict 4pt grid (#493). The scale is 4 / 8 / 12 / 16 / 20 / 24 / 32 → <code>--space-1</code> (2) · <code>--space-2</code> (4) · <code>--space-3</code> (8) · <code>--space-4</code> (12) · <code>--space-5</code> (16) · <code>--space-6</code> (20) · <code>--space-7</code> (24) · <code>--space-8</code> (32).</p><p>No off-grid values. The CI lint guards against new violations.</p><h2 id="screenshots" tabindex="-1">Screenshots <a class="header-anchor" href="#screenshots" aria-label="Permalink to &quot;Screenshots&quot;">​</a></h2><p>The README hero and <code>docs/screenshots/clawterm.png</code> are the canonical product images. When updating:</p><ul><li>Same window dimensions as the existing image (1280×800-ish, native macOS chrome cropped).</li><li>Same demo content: a project with three tabs in mixed states (running / waiting / errored), one tab expanded showing a split.</li><li>Dark wallpaper, traffic lights visible, no other windows.</li><li>Take both the hero and <code>docs/screenshots/*.png</code> in the same session — they should look like the same ClawTerm.</li></ul><h2 id="non-goals" tabindex="-1">Non-goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to &quot;Non-goals&quot;">​</a></h2><ul><li>Renaming the GitHub org or repo (<code>clawterm/clawterm</code> stays).</li><li>Domain change. Custom domain is a separate decision.</li><li>New illustrations or marketing motion graphics.</li><li>Color expansion beyond the documented tokens.</li><li>Hand-built clean SVG source for the mark — possible follow-up, not blocking.</li></ul>',47)])])}const p=o(n,[["render",s]]);export{g as __pageData,p as default};
